3.1.11 AbstractUserDetailsAuthenticationProvider
一个基本的 AuthenticationProvider，它允许子类覆盖和使用 UserDetails 对象。该类旨在响应 UsernamePasswordAuthenticationToken 身份验证请求。
成功验证后，将创建一个 UsernamePasswordAuthenticationToken 并将其返回给调用者。Token 将包括作为其主体的用户名的字符串表示形式或从身份验证存储库返回的 UserDetails。
如果正在使用容器适配器，则适合使用 String ，因为它需要 String 表示用户名。如果需要访问经过身份验证的用户的其他属性，例如电子邮件地址、人性化名称等，则适合使用 UserDetails。由于不建议使用容器适配器，并且 UserDetails 实现提供了额外的灵活性，默认情况下会返回 UserDetails。要覆盖此默认值，可以将 setForcePrincipalAsString 设置为 true。
通过存储放置在 UserCache 中的 UserDetails 对象来处理缓存。这确保了可以验证具有相同用户名的后续请求，而无需查询 UserDetailsService。但需要注意的是，如果用户出现密码错误，将查询 UserDetailsService 以确认是否使用了最新密码进行比较。只有无状态应用程序才可能需要缓存。例如，在普通的 Web 应用程序中，SecurityContext 存储在用户的会话中，并且用户不会在每个请求上重新进行身份验证。因此，默认缓存实现是 NullUserCache。public abstract class AbstractUserDetailsAuthenticationProvider implements AuthenticationProvider, InitializingBean, MessageSourceAware &#123;

    public Authentication authenticate(Authentication authentication) throws AuthenticationException &#123;
        Assert.isInstanceOf(UsernamePasswordAuthenticationToken.class, authentication,
                messages.getMessage(
                        &quot;AbstractUserDetailsAuthenticationProvider.onlySupports&quot;,
                        &quot;Only UsernamePasswordAuthenticationToken is supported&quot;));

        &#x2F;&#x2F; Determine username
        String username &#x3D; (authentication.getPrincipal() &#x3D;&#x3D; null) ? &quot;NONE_PROVIDED&quot; : authentication.getName();

        boolean cacheWasUsed &#x3D; true;

        &#x2F;&#x2F; 1. 默认从缓存中获取 UserDetails 信息
        UserDetails user &#x3D; this.userCache.getUserFromCache(username);

        if (user &#x3D;&#x3D; null) &#123;
            cacheWasUsed &#x3D; false;

            try &#123;
                &#x2F;&#x2F; 2. 缓存中拿不到就从数据库中获取 UserDetails 信息 默认实现是 DaoAuthenticationProvider 的 retrieveUser方法
                user &#x3D; retrieveUser(username, (UsernamePasswordAuthenticationToken) authentication);
            &#125;
            catch (UsernameNotFoundException notFound) &#123;
                logger.debug(&quot;User &#39;&quot; + username + &quot;&#39; not found&quot;);

                if (hideUserNotFoundExceptions) &#123;
                    throw new BadCredentialsException(messages.getMessage(
                            &quot;AbstractUserDetailsAuthenticationProvider.badCredentials&quot;,
                            &quot;Bad credentials&quot;));
                &#125;
                else &#123;
                    throw notFound;
                &#125;
            &#125;

            Assert.notNull(user, &quot;retrieveUser returned null - a violation of the interface contract&quot;);
        &#125;

        try &#123;
            &#x2F;&#x2F; 3. 检查 User 的各种状态, 用户过期, 密码过期等
            preAuthenticationChecks.check(user);
            &#x2F;&#x2F; 4. 密码匹配校验, 调用加密类 PasswordEncoder (可以自己定义)
            additionalAuthenticationChecks(user, (UsernamePasswordAuthenticationToken) authentication);
        &#125;
        catch (AuthenticationException exception) &#123;
            if (cacheWasUsed) &#123;
                &#x2F;&#x2F; There was a problem, so try again after checking
                &#x2F;&#x2F; we&#39;re using latest data (i.e. not from the cache)
                cacheWasUsed &#x3D; false;
                user &#x3D; retrieveUser(username, (UsernamePasswordAuthenticationToken) authentication);
                preAuthenticationChecks.check(user);
                additionalAuthenticationChecks(user, (UsernamePasswordAuthenticationToken) authentication);
            &#125;
            else &#123;
                throw exception;
            &#125;
        &#125;

        &#x2F;&#x2F; 5. 检查一下一些数据是否过期
        postAuthenticationChecks.check(user);

        if (!cacheWasUsed) &#123;
            &#x2F;&#x2F; 6. 将 UserDetails 放入缓存
            this.userCache.putUserInCache(user);
        &#125;

        Object principalToReturn &#x3D; user;

        if (forcePrincipalAsString) &#123;
            principalToReturn &#x3D; user.getUsername();
        &#125;

        &#x2F;&#x2F; 7. 将用户所有的所有合法角色放入 Token 中的 authorities 中 并且 authenticated 设置为true 表示验证通过了
        return createSuccessAuthentication(principalToReturn, authentication, user);
    &#125;
&#125;

