                    params:&#123;
                        username:&quot;admin&quot;,
                        password:&quot;123456&quot;
                    &#125;
                &#125;).then(function (response) &#123;
                    alert(response.data);
                &#125;);
                event.preventDefault();
            &#125;
        &#125;
    &#125;);
&lt;&#x2F;script&gt;
控制器方法： @RequestMapping(&quot;&#x2F;testAjax&quot;)
@ResponseBody
public String testAjax(String username, String password)&#123;
    System.out.println(&quot;username:&quot;+username+&quot;,password:&quot;+password);
