3.2 Dao层public interface UserDao &#123;
    User selectUser(int id); &#x2F;&#x2F; 按id 查询
    List&lt;User&gt; selectAll(); &#x2F;&#x2F; 查询所有
    int selectTotalCount(); &#x2F;&#x2F; 查询总记录条数
