public class OrderServiceImpl implements OrderService &#123;
    @Transactional
    public void updateOrder(Order order) &#123;
        try &#123;
            &#x2F;&#x2F; update order
        &#125; catch &#123;
			&#x2F;&#x2F; 异常被 catch，但又不抛出来
        &#125;
    &#125;
&#125;
