2.3.3 全局 Axios 拦截器1. 在 src 目录下新建 axios.js 文件，拦截所有请求，对于 200 状态码的请求放行，对其他状态码请求进行处理
import axios from &quot;axios&quot;;
import ElementUI from &quot;element-ui&quot;;
import router from &quot;.&#x2F;router&quot;;

const request &#x3D; axios.create(&#123;
  timeout: 5000,
  headers: &#123;
    &quot;Content-Type&quot;: &quot;application&#x2F;json&quot;,
  &#125;,
&#125;);

request.interceptors.request.use(config &#x3D;&gt; &#123;
  if (localStorage.getItem(&quot;token&quot;)) &#123;
  	&#x2F;&#x2F; 请求头带上 token
    config.headers.Authorization &#x3D; localStorage.getItem(&quot;jwt&quot;);
  &#125;
  return config;
&#125;);

request.interceptors.response.use(response &#x3D;&gt; &#123;
  let res &#x3D; response.data;

  if (res.code &#x3D;&#x3D;&#x3D; 200) &#123;
    return response;
  &#125;else &#123;
    ElementUI.Message.error(res.message ? res.message : &#39;系统异常&#39;);
    return Promise.reject(res.message);
  &#125;
&#125;, error &#x3D;&gt; &#123;
  if (error.response) &#123;
    switch (error.response.status) &#123;
      case 401:
        router.push(&quot;&#x2F;login&quot;);
        break;
      case 403:
        ElementUI.Message.error(&quot;拒绝访问&quot;);
        break;
      case 404:
        ElementUI.Message.error(&quot;请求错误,未找到该资源&quot;);
        break;
      case 500:
        ElementUI.Message.error(&quot;服务器出错&quot;);
        break;
      default:
        ElementUI.Message.error(&quot;未知错误&quot;);
    &#125;
  &#125;
  return Promise.reject(error);
&#125;);

export default request
