router.beforeEach((to, from, next) &#x3D;&gt; &#123;
  let hasRoute &#x3D; store.state.menu.hasRoute;
  if (to.path &#x3D;&#x3D;&#x3D; &#39;&#x2F;login&#39;) &#123;
    next();
  &#125; else if(!localStorage.getItem(&#39;jwt&#39;))&#123;
    next(&#39;&#x2F;login&#39;);
  &#125; else if (!hasRoute)&#123;
    axios.get(&#39;&#x2F;hrms&#x2F;sys&#x2F;menu&#x2F;getNavMenu&#39;).then(res &#x3D;&gt; &#123;
      &#x2F;&#x2F; 拿到 menuList 菜单列表
