      &#x2F;&#x2F; 动态绑定路由
      res.data.data.menuList.forEach(menu &#x3D;&gt; &#123;
        if (menu.children) &#123;
          menu.children.forEach(child &#x3D;&gt; &#123;
            &#x2F;&#x2F; 转成路由
