  &#125;else &#123;
    next();
  &#125;
&#125;)

const menuToRouter &#x3D; (menu) &#x3D;&gt; &#123;
  if(!menu.component)&#123;
    return null;
  &#125; else &#123;
    return &#123;
      path: menu.path,
