3.2.2 RedisConfig 配置类重新定义 Redis 的序列化规则。将 RedisTemplate 的 Key 的序列化规则设为 StringRedisSerializer，Value 的序列化规则设为 Jackson2JsonRedisSerializer
关于 Redis 序列化规则参考：https://blog.csdn.net/ACE_U_005A&#x2F;article&#x2F;details&#x2F;124565124
@Configuration
public class RedisConfig &#123;

    @Bean
    RedisTemplate redisTemplate(RedisConnectionFactory redisConnectionFactory) &#123;
        RedisTemplate redisTemplate &#x3D; new RedisTemplate();
        redisTemplate.setConnectionFactory(redisConnectionFactory);

        Jackson2JsonRedisSerializer jackson2JsonRedisSerializer &#x3D; new Jackson2JsonRedisSerializer(Object.class);
        redisTemplate.setDefaultSerializer(jackson2JsonRedisSerializer);

        redisTemplate.setKeySerializer(new StringRedisSerializer());
        redisTemplate.setValueSerializer(jackson2JsonRedisSerializer);

        redisTemplate.setHashKeySerializer(new StringRedisSerializer());
        redisTemplate.setHashValueSerializer(jackson2JsonRedisSerializer);

        return redisTemplate;
    &#125;
&#125;
3.2.3 CorsConfig 跨域配置类浏览器出于安全的考虑，使用 XMLHttpRequest 对象发起 HTTP 请求时必须遵守同源策略，否则就是跨域的 HTTP 请求，默认情况下是被禁止的。同源策略要求源相同才能正常进行通信，即协议、域名、端口号都完全一致。 
前后端分离项目，前端项目和后端项目一般都不是同源的，所以肯定会存在跨域请求的问题，需要进行处理让前端能进行跨域请求。
@Configuration
public class CorsConfig implements WebMvcConfigurer &#123;

    private CorsConfiguration buildConfig() &#123;
        CorsConfiguration corsConfiguration &#x3D; new CorsConfiguration();
        corsConfiguration.addAllowedOrigin(&quot;*&quot;); &#x2F;&#x2F; 允许所有来源
        corsConfiguration.addAllowedHeader(&quot;*&quot;); &#x2F;&#x2F; 允许所有请求头
        corsConfiguration.addAllowedMethod(&quot;*&quot;); &#x2F;&#x2F; 允许所有方法
        corsConfiguration.addExposedHeader(&quot;Authorization&quot;);
        return corsConfiguration;
    &#125;

    @Bean
    public CorsFilter corsFilter() &#123;
        UrlBasedCorsConfigurationSource urlBasedCorsConfigurationSource &#x3D; new UrlBasedCorsConfigurationSource();
        urlBasedCorsConfigurationSource.registerCorsConfiguration(&quot;&#x2F;**&quot;, buildConfig());
        return new CorsFilter(urlBasedCorsConfigurationSource);
    &#125;

    @Override
    public void addCorsMappings(CorsRegistry registry) &#123;
        &#x2F;&#x2F; 设置允许跨域的路径
        registry.addMapping(&quot;&#x2F;**&quot;)
                &#x2F;&#x2F; 设置允许跨域请求的域名
                .allowedOriginPatterns(&quot;*&quot;)
                &#x2F;&#x2F; 是否允许 cookie
&#x2F;&#x2F;                .allowCredentials(true)
                &#x2F;&#x2F; 设置允许的请求方式
                .allowedMethods(&quot;GET&quot;, &quot;POST&quot;, &quot;DELETE&quot;, &quot;PUT&quot;)
                &#x2F;&#x2F; 设置允许的 header 属性
                .allowedHeaders(&quot;*&quot;)
                &#x2F;&#x2F; 跨域允许时间
                .maxAge(3600);
    &#125;
&#125;
