  name: &#39;App&#39;,
  methods: &#123;
    getStudents() &#123;
      &#x2F;&#x2F; 加上前缀 &#x2F;fan，才会被匹配到走代理
      axios.get(&#39;&#x2F;fan&#x2F;students&#39;).then(
        response &#x3D;&gt; &#123;
          console.log(&#39;请求成功了&#39;, response.data)
        &#125;,
        error &#x3D;&gt; &#123;
