import &#123; mapState, mapGetters, mapActions, mapMutations &#125; from &#39;vuex&#39;

export default &#123;
  &#x2F;&#x2F; eslint-disable-next-line vue&#x2F;multi-word-component-names
  name: &#39;Count&#39;,
