      data: &#123;
        keyWord: &#39;&#39;,
        sortType: 0,
        persons:[
			&#123;id:&#39;001&#39;,name:&#39;马冬梅&#39;,age:34,sex:&#39;女&#39;&#125;,
			&#123;id:&#39;002&#39;,name:&#39;周冬雨&#39;,age:22,sex:&#39;女&#39;&#125;,
			&#123;id:&#39;003&#39;,name:&#39;周杰伦&#39;,age:47,sex:&#39;男&#39;&#125;,
			&#123;id:&#39;004&#39;,name:&#39;温兆伦&#39;,age:22,sex:&#39;男&#39;&#125;
		],
      &#125;,
      computed: &#123;
        filterPersons()&#123;
          let arr &#x3D; this.persons.filter((p) &#x3D;&gt; &#123;
            return p.name.indexOf(this.keyWord) !&#x3D;&#x3D; -1;
          &#125;)
          if(this.sortType)&#123;
            arr.sort((p1, p2) &#x3D;&gt; &#123;
              return this.sortType &#x3D;&#x3D;&#x3D; 1 ? p1.age - p2.age : p2.age - p1.age
            &#125;)
          &#125;
          return arr;
        &#125;
      &#125;
    &#125;);
  &lt;&#x2F;script&gt;
点击升序，sortType &#x3D;&#x3D;&#x3D; 2，p1.age - p2.age点击降序，sortType &#x3D;&#x3D;&#x3D; 1，p2.age - p1.age原顺序，sortType &#x3D;&#x3D;&#x3D; 0，返回原数组不进行排序过滤后排序
12.5 Vue 数据监测原理
Vue 会监视 data 中所有层次的数据
如何监测对象中的数据？ 通过 setter 实现监视，且要在 new Vue 时就传入要监测的数据
对象中后追加的属性，Vue 默认不做响应式处理
如需给后添加的属性做响应式，需使用如下API： 1. Vue.set(target，propertyName&#x2F;index，value) 或 2. vm.$set(target，propertyName&#x2F;index，value)


如何监测数组中的数据？ 通过包裹数组更新元素的方法实现，本质就是做了两件事：
调用原生对应的方法对数组进行更新。
重新解析模板，进而更新页面。


在 Vue 修改数组中的某个元素一定要用如下方法：
使用这些API，会改变原来的数组

 push()、pop()、shift()、unshift()、splice()、sort()、reverse()  2. Vue.set() 或 vm.$set()

使用 filter()、concat() 和 slice() 等方法不会改变原来的数组，可以用返回的新数组替换旧数组 

注：Vue.set() 和 vm.$set() 不能给 vm 或 vm 的根数据对象（vm._data）添加属性！！！
&lt;body&gt;
  &lt;!-- 准备好一个容器--&gt;
  &lt;div id&#x3D;&quot;root&quot;&gt;
    &lt;h1&gt;学生信息&lt;&#x2F;h1&gt;
    &lt;button @click&#x3D;&quot;student.age++&quot;&gt;年龄+1岁&lt;&#x2F;button&gt; &lt;br&#x2F;&gt;
		&lt;button @click&#x3D;&quot;addSex&quot;&gt;添加性别属性，默认值：男&lt;&#x2F;button&gt; &lt;br&#x2F;&gt;
		&lt;button @click&#x3D;&quot;student.sex &#x3D; &#39;未知&#39; &quot;&gt;修改性别&lt;&#x2F;button&gt; &lt;br&#x2F;&gt;
		&lt;button @click&#x3D;&quot;addFriend&quot;&gt;在列表首位添加一个朋友&lt;&#x2F;button&gt; &lt;br&#x2F;&gt;
		&lt;button @click&#x3D;&quot;updateFirstFriendName&quot;&gt;修改第一个朋友的名字为：张三&lt;&#x2F;button&gt; &lt;br&#x2F;&gt;
		&lt;button @click&#x3D;&quot;addHobby&quot;&gt;添加一个爱好&lt;&#x2F;button&gt; &lt;br&#x2F;&gt;
		&lt;button @click&#x3D;&quot;updateHobby&quot;&gt;修改第一个爱好为：开车&lt;&#x2F;button&gt; &lt;br&#x2F;&gt;
		&lt;button @click&#x3D;&quot;removeSmoke&quot;&gt;过滤掉爱好中的抽烟&lt;&#x2F;button&gt; &lt;br&#x2F;&gt;
    &lt;h3&gt;姓名：&#123;&#123;student.name&#125;&#125;&lt;&#x2F;h3&gt;
			&lt;h3&gt;年龄：&#123;&#123;student.age&#125;&#125;&lt;&#x2F;h3&gt;
			&lt;h3 v-if&#x3D;&quot;student.sex&quot;&gt;性别：&#123;&#123;student.sex&#125;&#125;&lt;&#x2F;h3&gt;
			&lt;h3&gt;爱好：&lt;&#x2F;h3&gt;
			&lt;ul&gt;
				&lt;li v-for&#x3D;&quot;(hobby,index) in student.hobbys&quot; :key&#x3D;&quot;index&quot;&gt;
					&#123;&#123;hobby&#125;&#125;
				&lt;&#x2F;li&gt;
			&lt;&#x2F;ul&gt;
			&lt;h3&gt;朋友们：&lt;&#x2F;h3&gt;
			&lt;ul&gt;
				&lt;li v-for&#x3D;&quot;(f,index) in student.friends&quot; :key&#x3D;&quot;index&quot;&gt;
					&#123;&#123;f.name&#125;&#125;--&#123;&#123;f.age&#125;&#125;
				&lt;&#x2F;li&gt;
			&lt;&#x2F;ul&gt;
  &lt;&#x2F;div&gt;
&lt;&#x2F;body&gt;
&lt;script type&#x3D;&quot;text&#x2F;javascript&quot;&gt;
  Vue.config.productionTip &#x3D; false &#x2F;&#x2F;阻止 vue 在启动时生成生产提示。

  const vm &#x3D; new Vue(&#123;
    el:&#39;#root&#39;,
    data:&#123;
		student:&#123;
			name:&#39;tom&#39;,
			age:18,
			hobbys:[&#39;抽烟&#39;,&#39;喝酒&#39;,&#39;烫头&#39;],
			friends:[
				&#123;name:&#39;jerry&#39;,age:35&#125;,
				&#123;name:&#39;tony&#39;,age:36&#125;
			]
		&#125;
	&#125;,
    methods: &#123;
      addSex()&#123;
        Vue.set(vm.student, &#39;sex&#39;, &#39;男&#39;) &#x2F;&#x2F; this.student &#x3D;&#x3D;&#x3D; vm._data.student &#x3D;&#x3D;&#x3D; vm.student
        &#x2F;&#x2F; this.$set(this.student, &#39;sex&#39;, &#39;男&#39;) this &#x3D;&#x3D;&#x3D; vm
      &#125;,
      addFriend()&#123;
        this.student.friends.unshift(&#123;name:&#39;jack&#39;,age:24&#125;)
      &#125;,
      updateFirstFriendName()&#123;
        this.student.friends[0].name &#x3D; &#39;张三&#39;
      &#125;,
      addHobby()&#123;
        this.student.hobbys.push(&#39;学习&#39;)
      &#125;,
      updateHobby()&#123;
        &#x2F;&#x2F; this.student.hobbys.splice(0,1,&#39;开车&#39;) 从第 0 个开始删一个，删完之后再插入一个新的
        &#x2F;&#x2F; Vue.set(this.student.hobbys, 0, &#39;开车&#39;)
        this.$set(this.student.hobbys, 0, &#39;开车&#39;)
      &#125;,
      removeSmoke()&#123;
        this.student.hobbys &#x3D; this.student.hobbys.filter((hobby) &#x3D;&gt; &#123;
